#include <bits/stdc++.h>
using namespace std;
class Node {
public:
    int key, value;
    Node* prev;
    Node* next;
    Node(int k, int v) : key(k), value(v), prev(nullptr), next(nullptr) {}
};
class LRUCache {
private:
    int capacity;
    unordered_map<int, Node*> cache;
    Node* head;
    Node* tail;
public:
    LRUCache(int capacity) {
        this->capacity = capacity;
        head = new Node(0, 0);
        tail = new Node(0, 0);
        head->next = tail;
        tail->prev = head;
    }
    ~LRUCache() {
        while (head->next != tail) {
            Node* node = head->next;
            head->next = node->next;
            node->next->prev = head;
            delete node;
        }
        delete head;
        delete tail;
    }
    int get(int key) {
        if (cache.find(key) != cache.end()) {
            Node* node = cache[key];
            remove(node);
            add(node);
            return node->value;
        }
        return -1;
    }
    void put(int key, int value) {
        if (cache.find(key) != cache.end()) {
            Node* node = cache[key];
            node->value = value;
            remove(node);
            add(node);
        } else {
            if (cache.size() == capacity) {
                cache.erase(tail->prev->key);
                remove(tail->prev);
            }
            Node* node = new Node(key, value);
            add(node);
            cache[key] = node;
        }
    }
    void remove(Node* node) {
        Node* prev = node->prev;
        Node* next = node->next;
        prev->next = next;
        next->prev = prev;
    }
    void add(Node* node) {
        Node* prev = head;
        Node* next = head->next;
        prev->next = node;
        next->prev = node;
        node->prev = prev;
        node->next = next;
    }
};
class Solution {
public:
    vector<int> solve(int capacity, vector<vector<string>>& operations) {
        LRUCache cache(capacity);
        vector<int> result;
        for (const auto& op : operations) {
            if (op[0] == "GET") {
                result.push_back(cache.get(stoi(op[1])));
            } else {
                cache.put(stoi(op[1]), stoi(op[2]));
            }
        }
        return result;
    }
};

