import java.util.*;
class Node {
    int key, value;
    Node prev, next;
    Node(int k, int v) {
        key = k;
        value = v;
    }
}
class LRUCache {
    private int capacity;
    private HashMap<Integer, Node> cache;
    private Node head, tail;
    public LRUCache(int capacity) {
        this.capacity = capacity;
        cache = new HashMap<>();
        head = new Node(0, 0);
        tail = new Node(0, 0);
        head.next = tail;
        tail.prev = head;
    }
    public int get(int key) {
        if (cache.containsKey(key)) {
            Node node = cache.get(key);
            remove(node);
            add(node);
            return node.value;
        }
        return -1;
    }
    public void put(int key, int value) {
        if (cache.containsKey(key)) {
            Node node = cache.get(key);
            node.value = value;
            remove(node);
            add(node);
        } else {
            if (cache.size() == capacity) {
                cache.remove(tail.prev.key);
                remove(tail.prev);
            }
            Node node = new Node(key, value);
            add(node);
            cache.put(key, node);
        }
    }
    private void remove(Node node) {
        Node prev = node.prev;
        Node next = node.next;
        prev.next = next;
        next.prev = prev;
    }
    private void add(Node node) {
        Node prev = head;
        Node next = head.next;
        prev.next = node;
        next.prev = node;
        node.prev = prev;
        node.next = next;
    }
}
class Solution {
    public int[] solve(int capacity, String[] operations) {
        LRUCache cache = new LRUCache(capacity);
        int[] result = new int[operations.length];
        int j = 0;
        for (String op : operations) {
            String[] parts = op.split(" ");
            if (parts[0].equals("GET")) {
                result[j++] = cache.get(Integer.parseInt(parts[1]));
            } else {
                cache.put(Integer.parseInt(parts[1]), Integer.parseInt(parts[2]));
            }
        }
        return result;
    }
}

