    def solve(self, capacity: int, operations: list[list[str]]) -> list[int]:
        cache = OrderedDict()
        results = []
        for op in operations:
            if op[0] == 'GET':
                key = int(op[1])
                if key in cache:
                    value = cache.pop(key)
                    cache[key] = value
                    results.append(value)
                else:
                    results.append(-1)
            elif op[0] == 'PUT':
                key, value = int(op[1]), int(op[2])
                if key in cache:
                    cache.pop(key)
                elif len(cache) >= capacity:
                    cache.popitem(last=False)
                cache[key] = value
        return results

