#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> solve(int capacity, vector<vector<string>>& operations) {
        unordered_map<int, int> cache;
        list<int> order;
        vector<int> results;
        for (const auto& op : operations) {
            if (op[0] == "GET") {
                int key = stoi(op[1]);
                if (cache.count(key)) {
                    order.remove(key);
                    order.push_back(key);
                    results.push_back(cache[key]);
                } else {
                    results.push_back(-1);
                }
            } else if (op[0] == "PUT") {
                int key = stoi(op[1]), value = stoi(op[2]);
                if (cache.count(key)) {
                    order.remove(key);
                } else if (cache.size() >= capacity) {
                    cache.erase(order.front());
                    order.pop_front();
                }
                cache[key] = value;
                order.push_back(key);
            }
        }
        return results;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int capacity, n;
    cin >> capacity >> n;
    vector<vector<string>> operations(n);
    for (int i = 0; i < n; i++) {
        string op;
        cin >> op;
        operations[i].push_back(op);
        if (op == "GET") {
            int key;
            cin >> key;
            operations[i].push_back(to_string(key));
        } else {
            int key, value;
            cin >> key >> value;
            operations[i].push_back(to_string(key));
            operations[i].push_back(to_string(value));
        }
    }
    Solution sol;
    vector<int> ans = sol.solve(capacity, operations);
    for (int val : ans) {
        cout << val << "\n";
    }
    return 0;
}
